package io.spdigital.skalbox.chart.web.controller;

import io.spdigital.skalbox.chart.exception.ChartApiException;
import io.spdigital.skalbox.chart.model.dto.BDLChart;
import io.spdigital.skalbox.chart.model.dto.BillExplainer;
import io.spdigital.skalbox.chart.model.dto.ChartConstants;
import io.spdigital.skalbox.chart.model.dto.MDHChart;
import io.spdigital.skalbox.chart.model.dto.MDHChart.MDHChartRequest;
import io.spdigital.skalbox.chart.model.dto.MDHChart.MDHChartResponse;
import io.spdigital.skalbox.chart.scheduler.TariffScheduler;
import io.spdigital.skalbox.chart.service.ChartService;
import io.spdigital.skalbox.data.redis.TariffRepositoryImpl;
import io.spdigital.skalbox.service.sap.SAPService;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.test.context.bean.override.mockito.MockitoBean;
import org.springframework.web.server.ServerWebExchange;
import reactor.core.publisher.Mono;
import reactor.test.StepVerifier;

import java.util.Arrays;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.ArgumentMatchers.eq;
import static org.mockito.Mockito.when;

@SpringBootTest(classes = { ChartController.class })
class ChartControllerTest {

	@MockitoBean
	private ServerWebExchange exchange;

	@MockitoBean
	private ChartService chartService;

	@Autowired
	private ChartController chartController;

	@MockitoBean
	private TariffScheduler tariffScheduler;

	@MockitoBean
	SAPService sapService;

	@MockitoBean
	TariffRepositoryImpl tariffRepository;

	MDHChartRequest monthlyReq;

	MDHChart.DailySKRequest dailySKRequest;

	BDLChart.Daily.Request dailyBDLRequest;

	MDHChart.HourlySKRequest hourlySKRequest;

	BDLChart.Hourly.Request hourlyBDLRequest;

	BillExplainer.SK.Request billExplainerReq;

	@BeforeEach
	void setup() {
		monthlyReq = MDHChartRequest.builder().ebsPremiseNo("P1").consumptionValue("2021").build();

		dailySKRequest = MDHChart.DailySKRequest.builder()
			.month("2021-12")
			.accountNos(Arrays.asList("ACC1", "ACC2"))
			.build();
		dailyBDLRequest = BDLChart.Daily.Request.getDailyRequestForGraph(dailySKRequest);

		hourlySKRequest = MDHChart.HourlySKRequest.builder()
			.date("2021-12-01")
			.accountNos(Arrays.asList("ACC1", "ACC2"))
			.build();
		hourlyBDLRequest = BDLChart.Hourly.Request.getHourlyRequestForGraph(hourlySKRequest);

		billExplainerReq = BillExplainer.SK.Request.builder().ebsPremiseNo("P1").consumptionMonth("2021-12-01").build();
		;
	}

	@Test
	void testMonthly_Success() {
		Mono<MDHChartResponse> resp = Mono.just(MDHChartResponse.builder().premiseType("PREM_TYPE1").build());

		when(chartService.retrieveMonthly(monthlyReq, exchange)).thenReturn(resp);

		StepVerifier.create(chartController.monthly(exchange, monthlyReq)).assertNext(response -> {
			assertEquals("PREM_TYPE1", response.getPremiseType());
		}).verifyComplete();
	}

	@Test
	void tesMonthly_Fail() {
		when(chartService.retrieveMonthly(monthlyReq, exchange))
			.thenReturn(Mono.error(new ChartApiException(ChartConstants.CHART_MONTHLY_JARVIS_ERROR, "", null)));

		StepVerifier.create(chartController.monthly(exchange, monthlyReq))
			.expectError(ChartApiException.class)
			.verify();
	}

	@Test
	void testDaily_Success() {
		Mono<MDHChartResponse> resp = Mono.just(MDHChartResponse.builder().premiseType("").build());
		when(chartService.retrieveDaily(dailyBDLRequest)).thenReturn(resp);

		StepVerifier.create(chartController.daily(dailySKRequest)).assertNext(response -> {
			assertEquals("", response.getPremiseType());
		}).verifyComplete();
	}

	@Test
	void tesDaily_Fail() {
		when(chartService.retrieveDaily(dailyBDLRequest))
			.thenReturn(Mono.error(new ChartApiException(ChartConstants.CHART_MONTHLY_JARVIS_ERROR, "", null)));

		StepVerifier.create(chartController.daily(dailySKRequest)).expectError(ChartApiException.class).verify();
	}

	@Test
	void testHourly_Success() {
		Mono<MDHChartResponse> resp = Mono.just(MDHChartResponse.builder().premiseType("").build());
		when(chartService.retrieveHourly(hourlyBDLRequest)).thenReturn(resp);

		StepVerifier.create(chartController.hourly(hourlySKRequest)).assertNext(response -> {
			assertEquals("", response.getPremiseType());
		}).verifyComplete();
	}

	@Test
	void tesHourly_Fail() {
		when(chartService.retrieveHourly(hourlyBDLRequest))
			.thenReturn(Mono.error(new ChartApiException(ChartConstants.CHART_MONTHLY_JARVIS_ERROR, "", null)));

		StepVerifier.create(chartController.hourly(hourlySKRequest)).expectError(ChartApiException.class).verify();
	}

	@Test
	void testLatestDataAvail_Success() {
		MDHChart.LatestDataAvailResponse resp = MDHChart.LatestDataAvailResponse.builder()
			.LatestDataAvail(true)
			.dataAvailMonths(Arrays.asList("2022-02-01", "2022-01-01"))
			.build();
		when(chartService.retrieveLatestDataAvail(monthlyReq, exchange)).thenReturn(Mono.just(resp));

		StepVerifier.create(chartController.retrieveLatestDataAvail(exchange, monthlyReq)).assertNext(response -> {
			assertTrue(response.isLatestDataAvail());
			assertEquals(2, response.getDataAvailMonths().size());
			assertEquals("2022-02-01", response.getDataAvailMonths().get(0));
		}).verifyComplete();
	}

	@Test
	void testLatestDataAvail_Fail() {
		when(chartService.retrieveLatestDataAvail(monthlyReq, exchange))
			.thenReturn(Mono.error(new ChartApiException(ChartConstants.CHART_MONTHLY_JARVIS_ERROR, "", null)));

		StepVerifier.create(chartController.retrieveLatestDataAvail(exchange, monthlyReq))
			.expectError(ChartApiException.class)
			.verify();
	}

	@Test
	void testBillExplainer_Success() {
		BillExplainer.SK.Response resp = BillExplainer.SK.Response.builder().premiseType("Type1").build();
		when(chartService.retrieveBillExplainer(exchange, billExplainerReq)).thenReturn(Mono.just(resp));

		StepVerifier.create(chartController.retrieveBillExplainer(exchange, billExplainerReq))
			.assertNext(response -> assertEquals("Type1", response.getPremiseType()))
			.verifyComplete();
	}

	@Test
	void testBillExplainer_Fail() {
		when(chartService.retrieveBillExplainer(exchange, billExplainerReq))
			.thenReturn(Mono.error(new ChartApiException(ChartConstants.CHART_MONTHLY_JARVIS_ERROR, "", null)));

		StepVerifier.create(chartController.retrieveBillExplainer(exchange, billExplainerReq))
			.expectError(ChartApiException.class)
			.verify();
	}

	@Test
	void testCacheTariff_Success() {
		Map<String, String> mTariffEntity = new HashMap<>() {
			{
				put("2021-01-01", ".25100000");
				put("2021-02-01", ".25100000");
				put("2021-03-01", ".25100000");
				put("2021-04-01", ".25200000");
				put("2021-05-01", ".25200000");
				put("2021-06-01", ".25200000");
				put("2021-07-01", ".25300000");
				put("2021-08-01", ".25300000");
				put("2021-09-01", ".25300000");
				put("2021-10-01", ".25400000");
				put("2021-11-01", ".25400000");
				put("2021-12-01", ".25400000");
				put("2022-01-01", ".25500000");
				put("2022-02-01", ".25500000");
				put("2022-03-01", ".25500000");
				put("2022-04-01", ".25600000");
				put("2022-05-01", ".25600000");
				put("2022-06-01", ".25600000");
			}
		};
		BillExplainer.TariffSAP.Response response = BillExplainer.TariffSAP.Response.builder()
			.tariffs(List.of(
					BillExplainer.TariffSAP.Tariff.builder()
						.dateFrom("2021-04-01")
						.dateTo("2021-06-31")
						.elect(".25800000")
						.build(),
					BillExplainer.TariffSAP.Tariff.builder()
						.dateFrom("2021-01-01")
						.dateTo("2021-03-31")
						.elect(".25800000")
						.build(),
					BillExplainer.TariffSAP.Tariff.builder()
						.dateFrom("2021-10-01")
						.dateTo("2021-12-31")
						.elect(".25800000")
						.build(),
					BillExplainer.TariffSAP.Tariff.builder()
						.dateFrom("2021-07-01")
						.dateTo("2021-09-31")
						.elect(".25800000")
						.build(),
					BillExplainer.TariffSAP.Tariff.builder()
						.dateFrom("2021-04-01")
						.dateTo("2021-06-31")
						.elect(".25800000")
						.build(),
					BillExplainer.TariffSAP.Tariff.builder()
						.dateFrom("2021-01-01")
						.dateTo("2021-03-31")
						.elect(".25800000")
						.build()))
			.build();
		Mockito
			.when(sapService.reactivePost(eq(BillExplainer.TariffSAP.PATH), any(),
					eq(BillExplainer.TariffSAP.Response.class)))
			.thenReturn(Mono.just(response));
		Mockito.when(tariffRepository.setAndGet(any(), any())).thenReturn(Mono.just(mTariffEntity));

		StepVerifier.create(chartController.cacheTariff()).consumeNextWith(actual -> {
			assertEquals(18, actual.size());
		});
	}

	@Test
	void testGetTariff_Success() {
		Mockito.when(tariffRepository.get()).thenReturn(Mono.just(new HashMap<>() {
			{
				put("2022-03-01", "25.44");
				put("2022-02-01", "25.44");
				put("2022-01-01", "25.44");
				put("2021-12-01", "24.11");
				put("2021-11-01", "24.11");
				put("2021-10-01", "24.11");
				put("2021-09-01", "23.38");
				put("2021-08-01", "23.38");
				put("2021-07-01", "23.38");
			}
		}));
		StepVerifier.create(chartController.getTariff()).consumeNextWith(actual -> {
			assertEquals(9, actual.size());
		});
	}

}

package io.spdigital.skalbox.chart.web.controller;

import io.spdigital.skalbox.chart.exception.ChartApiException;
import io.spdigital.skalbox.chart.model.dto.ChartConstants;
