import io.spdigital.skalbox.chart.service.ChartService;
import org.junit.jupiter.api.Test;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.test.context.bean.override.mockito.MockitoBean;
import org.springframework.web.server.ServerWebExchange;
import reactor.core.publisher.Mono;
import reactor.test.StepVerifier;

import java.util.ArrayList;
import java.util.Arrays;
import java.util.Scanner;

import static io.spdigital.skalbox.chart.model.dto.ChartConstants.*;
import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.mockito.Mockito.when;

@SpringBootTest(classes = PrivateChartController.class)
class PrivateChartControllerTest {

	@MockitoBean
	private ServerWebExchange exchange;

	@MockitoBean
	private ChartService chartService;

	@Autowired
	private PrivateChartController controller;

	@Test
	void testCsvMonthly_Success() {
		ResponseEntity<String> respStr = new ResponseEntity<>(TITLE_MSSL + TITLE_ELECT, HttpStatus.OK);
		MDHChartRequest request = MDHChartRequest.builder().ebsPremiseNo("P1").consumptionBy(CSV_MONTHLY).build();
		when(chartService.downloadMonthlyCsv(request, exchange)).thenReturn(Mono.just(respStr));

		StepVerifier.create(controller.csvMonthly(request, exchange)).consumeNextWith(actual -> {
			ArrayList<String> result = new ArrayList<>();
			try (Scanner scanner = new Scanner(actual.getBody())) {
				while (scanner.hasNext()) {
					result.add(scanner.nextLine());
				}
			}
			assertEquals(2, result.size());

		}).verifyComplete();
	}

	@Test
	void tesCsvMonthly_Fail() {
		MDHChartRequest request = MDHChartRequest.builder().ebsPremiseNo("P1").build();
		when(chartService.downloadMonthlyCsv(request, exchange))
			.thenReturn(Mono.error(new ChartApiException(ChartConstants.CHART_MONTHLY_JARVIS_ERROR, "", null)));

		StepVerifier.create(controller.csvMonthly(request, exchange)).expectError(ChartApiException.class).verify();
	}

	@Test
	void testCsvDaily_Success() {
		ResponseEntity<String> respStr = new ResponseEntity<>("\"Period\",\"Current\"\n", HttpStatus.OK);
		MDHChart.DailyHourlyCSVSKRequest request = MDHChart.DailyHourlyCSVSKRequest.builder()
			.accountNos(Arrays.asList("ACC1", "ACC2"))
			.consumptionBy(CSV_DAILY)
			.build();
		when(chartService.downloadDailyHourlyCsv(request)).thenReturn(Mono.just(respStr));

		StepVerifier.create(controller.csvDailyHourly(request)).consumeNextWith(actual -> {
			ArrayList<String> result = new ArrayList<>();
			try (Scanner scanner = new Scanner(actual.getBody())) {
				while (scanner.hasNext()) {
					result.add(scanner.nextLine());
				}
			}
			assertEquals(1, result.size());

		}).verifyComplete();
	}

	@Test
	void tesCsvDaily_Fail() {
		MDHChart.DailyHourlyCSVSKRequest request = MDHChart.DailyHourlyCSVSKRequest.builder()
			.accountNos(Arrays.asList("ACC1", "ACC2"))
			.consumptionBy(CSV_DAILY)
			.build();
		when(chartService.downloadDailyHourlyCsv(request))
			.thenReturn(Mono.error(new ChartApiException(ChartConstants.CHART_BDL_ERROR, "", null)));

		StepVerifier.create(controller.csvDailyHourly(request)).expectError(ChartApiException.class).verify();
	}

}

package io.spdigital.skalbox.chart.web.controller;

import io.spdigital.skalbox.chart.model.dto.MDHChart;
import io.spdigital.skalbox.chart.model.dto.MDHChart.MDHChartRequest;
import io.spdigital.skalbox.chart.service.ChartService;
import io.spdigital.skalbox.logging.Loggable;
import io.spdigital.skalbox.service.security.Field;
import io.spdigital.skalbox.web.common.security.SkalboxSecured;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;
import org.springframework.web.server.ServerWebExchange;
import reactor.core.publisher.Mono;

import static io.spdigital.skalbox.chart.model.dto.ChartConstants.CSV_MONTHLY;
import static io.spdigital.skalbox.web.common.SkalboxConstants.PRIVATE_ENDPOINT;

@Slf4j
@RestController
@RequiredArgsConstructor
@RequestMapping(PRIVATE_ENDPOINT)
public class PrivateChartController {

	private final ChartService chartService;

	@Loggable
	@PostMapping(value = "/charts/csv/monthly")
	@SkalboxSecured(field = Field.ACCOUNT_NO)
	public Mono<ResponseEntity<String>> csvMonthly(@RequestBody MDHChartRequest request, ServerWebExchange exchange) {
		request.setConsumptionBy(CSV_MONTHLY);
		return chartService.downloadMonthlyCsv(request, exchange);
	}

	@Loggable
	@PostMapping(value = "/charts/csv/dailyHourly")
	@SkalboxSecured(field = Field.ACCOUNT_NOS)
	public Mono<ResponseEntity<String>> csvDailyHourly(@RequestBody MDHChart.DailyHourlyCSVSKRequest request) {
		return chartService.downloadDailyHourlyCsv(request);
	}

}

package io.spdigital.skalbox.chart.web.controller;

import io.spdigital.skalbox.chart.model.dto.BDLChart;
import io.spdigital.skalbox.chart.model.dto.BillExplainer;
import io.spdigital.skalbox.chart.model.dto.MDHChart;
import io.spdigital.skalbox.chart.model.dto.MDHChart.MDHChartRequest;
import io.spdigital.skalbox.chart.model.dto.MDHChart.MDHChartResponse;
import io.spdigital.skalbox.chart.scheduler.TariffScheduler;
import io.spdigital.skalbox.chart.service.ChartService;
import io.spdigital.skalbox.logging.Loggable;
import io.spdigital.skalbox.service.security.Field;
import io.spdigital.skalbox.web.common.security.SkalboxSecured;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.web.bind.annotation.*;
import org.springframework.web.server.ServerWebExchange;
import reactor.core.publisher.Mono;

import java.util.Map;

@Slf4j
@RestController("charts")
@RequestMapping("/charts")
@RequiredArgsConstructor
public class ChartController {

	private final ChartService chartService;

	private final TariffScheduler tariffScheduler;

	@Loggable
	@PostMapping("/monthly")
	public Mono<MDHChartResponse> monthly(ServerWebExchange exchange, @RequestBody MDHChartRequest request) {
		return chartService.retrieveMonthly(request, exchange);
	}

	@Loggable
	@SkalboxSecured(field = Field.ACCOUNT_NOS)
	@GetMapping("/daily")
	public Mono<MDHChartResponse> daily(@RequestBody MDHChart.DailySKRequest request) {
		return chartService.retrieveDaily(BDLChart.Daily.Request.getDailyRequestForGraph(request));
	}

	@Loggable
	@SkalboxSecured(field = Field.ACCOUNT_NOS)
	@GetMapping("/hourly")
	public Mono<MDHChartResponse> hourly(@RequestBody MDHChart.HourlySKRequest request) {
		return chartService.retrieveHourly(BDLChart.Hourly.Request.getHourlyRequestForGraph(request));
	}

	@Loggable
	@PostMapping("/retrieveLatestDataAvail")
	public Mono<MDHChart.LatestDataAvailResponse> retrieveLatestDataAvail(ServerWebExchange exchange,
			@RequestBody MDHChartRequest request) {
		return chartService.retrieveLatestDataAvail(request, exchange);
	}

	@Loggable
	@PostMapping("/cacheTariff")
	public Mono<Map<String, String>> cacheTariff() {
		return tariffScheduler.cache();
	}

	@Loggable
	@PostMapping("/tariff")
	public Mono<Map<String, String>> getTariff() {
		return tariffScheduler.get();
	}

	@Loggable
	@PostMapping("/retrieveBillExplainer")
	public Mono<BillExplainer.SK.Response> retrieveBillExplainer(ServerWebExchange exchange,
			@RequestBody BillExplainer.SK.Request request) {
		return chartService.retrieveBillExplainer(exchange, request);
	}

}

package io.spdigital.skalbox.chart.service;

import io.spdigital.skalbox.auth.service.Auth0Service;
