import static io.spdigital.skalbox.util.Constants.PATTERN_YYYY_MM_DD;

@Slf4j
@Service
@RequiredArgsConstructor
public class ChartServiceImpl implements ChartService {

	@Value("${charts.latestAvailData}")
	int latestAvailData;

	private final ReactiveConnector reactiveConnector;

	private final CustomerDetailsService customerDetailsService;

	private final Auth0Service auth0Service;

	private final SapDateUtil dateUtil;

	private final TariffRepository tariffRepository;

	private final TariffScheduler tariffScheduler;

	Predicate<String> isDailyCSV = CSV_DAILY::equals;

	Predicate<String> hasMsslAccount = StringUtils::isNotEmpty;

	Predicate<String> isMssl = TITLE_MSSL::equals;

	Predicate<String> isEmpty = premNo -> StringUtils.isEmpty(premNo);

	private final List<String> zeroValues = Arrays.asList("0", "0.0");

	public Mono<MDHChartResponse> retrieveMonthly(MDHChartRequest req, ServerWebExchange exchange) {
		Mono<String> auth0Id = auth0Service.getAuth0Id(exchange);
		return retrieveMonthly(req, auth0Id);
	}

	public Mono<MDHChartResponse> retrieveMonthly(MDHChartRequest req, Mono<String> auth0Id) {
		Mono<MDHChartResponse> respForEbsPremise = auth0Id
			.flatMap(auth -> getMonthlyResponse(req.getEbsPremiseNo(), auth))
			.map(jarvisEbsResp -> MDHChartResponse.builder()
				.premiseType(jarvisEbsResp.getPremiseType())
				.usageUtilElec(convertJarvisDtoToSK(jarvisEbsResp.getUsageUtilElec()))
				.usageUtilGas(convertJarvisDtoToSK(jarvisEbsResp.getUsageUtilGas()))
				.usageUtilWater(convertJarvisDtoToSK(jarvisEbsResp.getUsageUtilWater()))
				.build());

		Mono<MDHChartResponse> respForMsslPremise = auth0Id
			.flatMap(auth -> getMonthlyResponse(req.getMsslPremiseNo(), auth))
			.map(jarvisMsslResp -> MDHChartResponse.builder()
				.premiseType(jarvisMsslResp.getPremiseType())
				.usageUtilElec(convertJarvisDtoToSK(jarvisMsslResp.getUsageUtilElec()))
				.usageUtilGas(convertJarvisDtoToSK(jarvisMsslResp.getUsageUtilGas()))
				.usageUtilWater(convertJarvisDtoToSK(jarvisMsslResp.getUsageUtilWater()))
				.build());

		return Mono.zip(respForEbsPremise, respForMsslPremise, auth0Id)
			.map(data -> handleEmptyDataForJarvis(
					getEbsMsslCombinedResponse(req, data.getT1(), data.getT2(), data.getT3()), req, data.getT3()));

	}

	private MDHChartResponse getEbsMsslCombinedResponse(MDHChartRequest req, MDHChartResponse ebsResp,
			MDHChartResponse msslResp, String auth0Id) {

		if (ebsResp.getUsageUtilElec().isEmpty() || msslResp.getUsageUtilElec().isEmpty()) {
			return ebsResp.getUsageUtilElec().isEmpty() ? (msslResp.getUsageUtilElec().isEmpty() ? ebsResp : msslResp)
					: ebsResp;
		}

		ebsResp.getUsageUtilElec().get().getConsumption().stream().forEach(ebsCon -> {
			ebsCon.setCurrent(
					msslResp.getUsageUtilElec().isPresent() ? ("" + (Double.parseDouble(msslResp.getUsageUtilElec()
						.get()
						.getConsumption()
						.stream()
						.filter(msslCon -> msslCon.getPeriod().equals(ebsCon.getPeriod()))
						.findFirst()
						.orElseGet(() -> ConsumptionData.builder().current("0.0").build())
						.getCurrent()) + Double.parseDouble(ebsCon.getCurrent()))) : ebsCon.getCurrent());
		});
		return ebsResp;

	}

	private MDHChartResponse handleEmptyDataForJarvis(MDHChartResponse response, MDHChartRequest req, String auth0Id) {
		if (!CSV_MONTHLY.equals(req.getConsumptionBy()) && response.getUsageUtilElec().isEmpty()
				&& response.getUsageUtilGas().isEmpty() && response.getUsageUtilWater().isEmpty()) {
			log.info("No data from Jarvis: retrieveMonthly: premise {}, error {}", req.getEbsPremiseNo());
			throw new ChartApiException(CHART_NO_DATA_MSG, CHART_JARVIS_NO_DATA,
					String.format("Auth0Id: %s, EbsPremiseNo: %s, MsslPremiseNo: %s", auth0Id, req.getEbsPremiseNo(),
							req.getMsslPremiseNo()));
		}
		// When downloading CSV, no need to filter data based on year
		String consumptionMonth = CSV_MONTHLY.equals(req.getConsumptionBy()) ? "" : req.getConsumptionValue();
		response.getUsageUtilElec()
			.ifPresent(usageUtil -> usageUtil
				.setConsumption(filterConsumptionData(response.getUsageUtilElec(), consumptionMonth)));
		response.getUsageUtilGas()
			.ifPresent(usageUtil -> usageUtil
				.setConsumption(filterConsumptionData(response.getUsageUtilGas(), consumptionMonth)));
		response.getUsageUtilWater()
			.ifPresent(usageUtil -> usageUtil
				.setConsumption(filterConsumptionData(response.getUsageUtilWater(), consumptionMonth)));

		return response;
	}

	private List<MDHChart.ConsumptionData> filterConsumptionData(Optional<MDHChart.UsageUtil> usageUtils,
			String consumption) {
		List<MDHChart.ConsumptionData> filteredDatas = new ArrayList<>();
		boolean isValidCurrentValFound = false;
		List<MDHChart.ConsumptionData> datas = usageUtils.get().getConsumption();

		for (MDHChart.ConsumptionData data : datas) {
			// Removing the first few data which have current = 0. Jarvis data is in
			// descending date order.
			if (!isValidCurrentValFound && !"0".equals(data.getCurrent())) {
				isValidCurrentValFound = true;
			}

			if (isValidCurrentValFound && data.getPeriod().startsWith(consumption)) {
				filteredDatas.add(data);
			}
		}
		filteredDatas.sort(Comparator.comparing(ConsumptionData::getPeriod));
		return filteredDatas;
	}

	private Mono<ResponseJarvis> getMonthlyResponse(String premiseNo, String auth0Id) {
		return Mono.just(premiseNo)
			.flatMap(premNo -> isEmpty.test(premNo) ? Mono.just(ResponseJarvis.builder().build()) : reactiveConnector
				.reactiveGet(ConnectionProperties.Host.JARVIS, MONTHLY_RETRIEVAL,
						Map.of("iam_id", Arrays.asList(auth0Id)), Map.of("PREMISE_NO", premNo), ResponseJarvis.class)
				.doOnError(ex -> log.warn("Error encountered for premiseNo: " + premNo + ", Msg: " + ex.getMessage()))
				.onErrorReturn(ResponseJarvis.builder().build()));
	}

	private Optional<UsageUtil> convertJarvisDtoToSK(UsageUtilJarvis usageUtilJarvis) {
		if (null == usageUtilJarvis) {
			return Optional.empty();
		}

		return usageUtilJarvis.getData()
			.stream()
			.filter(i -> !"0".equals(i.getConsumption().getCurrent()))
			.findFirst()
			.map(usageUtilJarvisData -> UsageUtil.builder()
				.unit(usageUtilJarvis.getData().get(0).getUnit())
				.comparisonMsg(usageUtilJarvis.getComparisonMsg())
				.comparisonMsgType(usageUtilJarvis.getComparisonMsgType())
				.comparisonType(usageUtilJarvis.getComparisonType())
				.current(usageUtilJarvisData.getConsumption().getCurrent())
				.efficient(usageUtilJarvisData.getPeerComparison().getEfficient())
				.neighbourhood(usageUtilJarvisData.getPeerComparison().getAverage())
				.consumption(usageUtilJarvis.getData()
					.stream()
					.map(usageUtilJarvisData1 -> ConsumptionData.builder()
						.current(usageUtilJarvisData1.getConsumption().getCurrent())
						.average(usageUtilJarvisData1.getPeerComparison().getAverage())
						.efficient(usageUtilJarvisData1.getPeerComparison().getEfficient())
						.period(dateUtil.format(dateUtil
							.parseDate(usageUtilJarvisData1.getPeriod(), FORMATTER_YYYY_MM_DD_T_HH_MM_SS_XXX)
							.get(), FORMATTER_YYYY_MM_DD))
						.status(usageUtilJarvisData1.getStatus())
						.build())
					.collect(Collectors.toList()))
				.build());
	}

	@Override
	public Mono<MDHChart.LatestDataAvailResponse> retrieveLatestDataAvail(MDHChartRequest req,
			ServerWebExchange exchange) {
		Mono<String> auth0Id = auth0Service.getAuth0Id(exchange);

		Mono<MDHChartResponse> respForEbsPremise = auth0Id
			.flatMap(auth -> getMonthlyResponse(req.getEbsPremiseNo(), auth))
			.map(jarvisEbsResp -> MDHChartResponse.builder()
				.usageUtilElec(convertJarvisDtoToSK(jarvisEbsResp.getUsageUtilElec()))
				.build());

		Mono<MDHChartResponse> respForMsslPremise = auth0Id
			.flatMap(auth -> getMonthlyResponse(req.getMsslPremiseNo(), auth))
			.map(jarvisMsslResp -> MDHChartResponse.builder()
				.usageUtilElec(convertJarvisDtoToSK(jarvisMsslResp.getUsageUtilElec()))
				.build());

		return Mono.zip(respForEbsPremise, respForMsslPremise, auth0Id)
			.map(data -> computeLatestDataAvail(
					getEbsMsslCombinedResponse(req, data.getT1(), data.getT2(), data.getT3()), req, data.getT3()));
	}

	private MDHChart.LatestDataAvailResponse computeLatestDataAvail(MDHChartResponse response, MDHChartRequest req,
			String auth0Id) {

		if (response.getUsageUtilElec().isEmpty()) {
			log.info("No data from Jarvis: isLatestDataAvail: ebs {}, mssl {}", req.getEbsPremiseNo(),
					req.getMsslPremiseNo());
			throw new ChartApiException(CHART_NO_DATA_MSG, CHART_JARVIS_NO_DATA,
					String.format("Auth0Id: %s, EbsPremiseNo: %s, MsslPremiseNo: %s", auth0Id, req.getEbsPremiseNo(),
							req.getMsslPremiseNo()));
		}

		List<ConsumptionData> cons = response.getUsageUtilElec().get().getConsumption();
		OptionalInt matchingIndex = IntStream.range(0, cons.size())
			.filter(m -> !"0".equals(cons.get(m).getCurrent()))
			.findFirst();
		LocalDate cutOffDate = LocalDate.now().withDayOfMonth(1).minusDays(1).minusMonths(latestAvailData);
		return MDHChart.LatestDataAvailResponse.builder()
			.LatestDataAvail(matchingIndex.isPresent()
					? (dateUtil.parseDate(cons.get(matchingIndex.getAsInt()).getPeriod()).isAfter(cutOffDate)
							&& !"0".equals(cons.get(matchingIndex.getAsInt() + 1).getCurrent()))
					: false)
			.dataAvailMonths(cons.stream().map(ConsumptionData::getPeriod).collect(Collectors.toList()))
			.build();
	}

	private MDHChartResponse handleEmptyElectDataFromJarvis(MDHChartResponse response, MDHChartRequest req,
			String auth0Id) {
		if (response.getUsageUtilElec().isEmpty()) {
			log.info("No data from Jarvis: retrieveMonthly: premise {}, error {}", req.getEbsPremiseNo());
			throw new ChartApiException(CHART_NO_DATA_MSG, CHART_JARVIS_NO_DATA,
					String.format("Auth0Id: %s, EbsPremiseNo: %s, MsslPremiseNo: %s", auth0Id, req.getEbsPremiseNo(),
							req.getMsslPremiseNo()));
		}
		return response;
	}

	@Override
	public Mono<BillExplainer.SK.Response> retrieveBillExplainer(ServerWebExchange exchange,
			BillExplainer.SK.Request request) {

		// Retrieving from Jarvis, handling only elect data
		Mono<MDHChartResponse> jarvisResp = Mono.just(request).flatMap(skReq -> {
			Mono<String> auth0Id = auth0Service.getAuth0Id(exchange);

			Mono<MDHChartResponse> respForEbsPremise = auth0Id
				.flatMap(auth -> getMonthlyResponse(request.getEbsPremiseNo(), auth))
				.map(jarvisEbsResp -> MDHChartResponse.builder()
					.premiseType(jarvisEbsResp.getPremiseType())
					.usageUtilElec(convertJarvisDtoToSK(jarvisEbsResp.getUsageUtilElec()))
					.build());

			Mono<MDHChartResponse> respForMsslPremise = auth0Id
				.flatMap(auth -> getMonthlyResponse(request.getMsslPremiseNo(), auth))
				.map(jarvisMsslResp -> MDHChartResponse.builder()
					.premiseType(jarvisMsslResp.getPremiseType())
					.usageUtilElec(convertJarvisDtoToSK(jarvisMsslResp.getUsageUtilElec()))
					.build());

			MDHChartRequest req = MDHChartRequest.builder()
				.ebsPremiseNo(request.getEbsPremiseNo())
				.msslPremiseNo(request.getMsslPremiseNo())
				.build();
			return Mono.zip(respForEbsPremise, respForMsslPremise, auth0Id)
				.map(data -> handleEmptyElectDataFromJarvis(
						getEbsMsslCombinedResponse(req, data.getT1(), data.getT2(), data.getT3()), req, data.getT3()));
		});

		// Retrieving from Bill Explainer
		Mono<BillExplainer.BI.Response> biResp = getBillExplainerResponse(request, jarvisResp);

		LocalDate currentMonthDay1 = dateUtil.parseDate(request.getConsumptionMonth(), PATTERN_YYYY_MM_DD).get();
		LocalDate earlierMonthDay1 = currentMonthDay1.minusMonths(1);
		String earlierMonthShort = earlierMonthDay1.getMonth().getDisplayName(TextStyle.SHORT, Locale.US);

		// Retrieving tariff from Redis
		Mono<BillExplainer.SK.Tariff> tariffMono = getTariffFromRedis(currentMonthDay1.format(FORMATTER_YYYY_MM_DD))
			.map(currentMonthTariffStr -> BillExplainer.SK.Tariff.builder()
				.currentMonthTariff(currentMonthTariffStr)
				.build())
			.flatMap(skTariff -> getTariffFromRedis(earlierMonthDay1.format(FORMATTER_YYYY_MM_DD))
				.flatMap(earlierMonthTariffStr -> {
					double currentMonTariffD = Double.parseDouble(skTariff.getCurrentMonthTariff());
					double earlierMonTariffD = Double.parseDouble(earlierMonthTariffStr);
					skTariff.setTariffDiff((Double.compare(currentMonTariffD, earlierMonTariffD) == 0) ? "No change"
							: ((Double.compare(currentMonTariffD, earlierMonTariffD) < 0))
									? ("-" + new DecimalFormat("0.0000").format(earlierMonTariffD - currentMonTariffD)
											+ " vs " + earlierMonthShort)
									: ("+" + new DecimalFormat("0.0000").format(currentMonTariffD - earlierMonTariffD)
											+ " vs " + earlierMonthShort));
					skTariff.setCurrentMonthTariff(
							new DecimalFormat("0.0000").format(Double.parseDouble(skTariff.getCurrentMonthTariff())));
					return Mono.just(skTariff);
				}));

		// Merging all responses
		return Mono.zip(jarvisResp, biResp, tariffMono).map(tuple -> {
			UsageUtil usageUtilElect = tuple.getT1().getUsageUtilElec().get();

			String consumptionDiff = "";
			String statusDiff = "";

			OptionalInt currMonIndex = IntStream.range(0, usageUtilElect.getConsumption().size())
				.filter(i -> request.getConsumptionMonth().equals(usageUtilElect.getConsumption().get(i).getPeriod()))
				.findFirst();
			if (currMonIndex.isPresent() && ((currMonIndex.getAsInt() + 1) < usageUtilElect.getConsumption().size())) {
				MDHChart.ConsumptionData currentMonthConData2 = usageUtilElect.getConsumption()
					.get(currMonIndex.getAsInt());
				MDHChart.ConsumptionData earlierMonthConData = usageUtilElect.getConsumption()
					.get(currMonIndex.getAsInt() + 1);
				int currentMonthConD = Math.round(Float.parseFloat(currentMonthConData2.getCurrent()));
				int earlierMonthConD = Math.round(Float.parseFloat(earlierMonthConData.getCurrent()));

				String earlierMonth = dateUtil.parseDate(earlierMonthConData.getPeriod(), PATTERN_YYYY_MM_DD)
					.get()
					.getMonth()
					.getDisplayName(TextStyle.SHORT, Locale.US);

				consumptionDiff = (currentMonthConD == earlierMonthConD) ? "No change"
						: ((currentMonthConD < earlierMonthConD)
								? ("-" + (earlierMonthConD - currentMonthConD) + " kWh vs " + earlierMonth)
								: ("+" + (currentMonthConD - earlierMonthConD) + " kWh vs " + earlierMonth));
				statusDiff = (currentMonthConData2.getStatus().equals(earlierMonthConData.getStatus()) ? "No change"
						: (earlierMonthConData.getStatus() + " in " + earlierMonth));
			}

			return BillExplainer.SK.Response.builder()
				.usageUtilElec(Optional.of(BillExplainer.SK.UsageUtil.builder()
					.unit(usageUtilElect.getUnit())
					.current(usageUtilElect.getCurrent())
					.efficient(usageUtilElect.getEfficient())
					.neighbourhood(usageUtilElect.getNeighbourhood())
					.comparisonMsg(usageUtilElect.getComparisonMsg())
					.comparisonMsgType(usageUtilElect.getComparisonMsgType())
					.comparisonType(usageUtilElect.getComparisonType())
					.consumption(usageUtilElect.getConsumption()
						.stream()
						.map(jv -> BillExplainer.SK.ConsumptionData.builder()
							.current(jv.getCurrent())
							.efficient(jv.getEfficient())
							.average(jv.getAverage())
							.period(jv.getPeriod())
							.status(jv.getStatus())
							.build())
						.collect(Collectors.toList()))
					.consumptionDiff(consumptionDiff)
					.statusDiff(statusDiff)
					.weather((null != tuple.getT2().getData()) ? tuple.getT2().getData().get(0) : "")
					.others((null != tuple.getT2().getData() && tuple.getT2().getData().size() == 2)
							? tuple.getT2().getData().get(1) : "")
					.tariff(tuple.getT3().getCurrentMonthTariff())
					.tariffDiff(tuple.getT3().getTariffDiff())
					.build()))
				.build();

		});
	}

	private Mono<BillExplainer.BI.Response> getBillExplainerResponse(BillExplainer.SK.Request request,
			Mono<MDHChartResponse> jarvisResp) {
		return jarvisResp.flatMap(resp -> {

			OptionalInt matchingIndex = IntStream.range(0, resp.getUsageUtilElec().get().getConsumption().size())
				.filter(m -> request.getConsumptionMonth()
					.equals(resp.getUsageUtilElec().get().getConsumption().get(m).getPeriod()))
				.findFirst();

			if (matchingIndex.isPresent()
					&& ((matchingIndex.getAsInt() + 6) <= resp.getUsageUtilElec().get().getConsumption().size())
					&& !(IntStream.range(matchingIndex.getAsInt(), matchingIndex.getAsInt() + 6)
						.filter(m -> zeroValues
							.contains(resp.getUsageUtilElec().get().getConsumption().get(m).getCurrent()))
						.findFirst()
						.isPresent())) {

				List<Map> biReqConsumption = new ArrayList<>();
				for (int k = matchingIndex.getAsInt(); k <= matchingIndex.getAsInt() + 5; k++) {
					MDHChart.ConsumptionData data = resp.getUsageUtilElec().get().getConsumption().get(k);
					biReqConsumption.add(new HashMap<>() {
						{
							put(data.getPeriod(), (int) Double.parseDouble(data.getCurrent()));
						}
					});
				}

				BillExplainer.BI.Request biReq = BillExplainer.BI.Request.builder()
					.acct(request.getEbsPremiseNo() + "," + request.getMsslPremiseNo())
					.consumption(biReqConsumption)
					.build();
				return reactiveConnector
					.reactivePost(ConnectionProperties.Host.BILLEXPLAINER, BILL_EXPLAINER, biReq,
							BillExplainer.BI.Response.class)
					.doOnError(throwable -> log.error("Error occurred: retrieveBillExplainer: path {}, request {}, {}",
							BILL_EXPLAINER, biReq, throwable.getMessage()))
					.onErrorResume(ex -> Mono.just(BillExplainer.BI.Response.builder().build()));
			}

			return Mono.just(BillExplainer.BI.Response.builder().build());
		});
	}

	private Mono<String> getTariffFromRedis(String date) {
		return tariffRepository.getTariff(date)
			.log("tariff from cache")
			.doOnError(throwable -> log.warn("getTariffFromRedis :: Tariff missing for {}, going to cache again", date))
			.onErrorReturn("")
			.filter(tariff -> StringUtils.isNotBlank(tariff))
			.switchIfEmpty(Mono.defer(() -> tariffScheduler.cache()
				.log("caching tarif....")
				.map(stringStringMap -> stringStringMap.get(date))));
	}

	@Override
