package io.spdigital.skalbox.chart.scheduler;

import io.spdigital.skalbox.chart.model.dto.BillExplainer.TariffSAP;
import io.spdigital.skalbox.chart.model.dto.BillExplainer.TariffSAP.Request;
import io.spdigital.skalbox.chart.model.dto.BillExplainer.TariffSAP.Response;
import io.spdigital.skalbox.chart.model.dto.ChartConstants;
import io.spdigital.skalbox.chart.utils.ChartDateUtil;
import io.spdigital.skalbox.data.redis.TariffEntity;
import io.spdigital.skalbox.data.redis.TariffRepository;
import io.spdigital.skalbox.service.sap.SAPService;
import io.spdigital.skalbox.util.Constants;
import java.time.LocalDate;
import java.time.temporal.ChronoUnit;
import java.util.Map;
import java.util.TreeMap;
import java.util.stream.Collectors;
import java.util.stream.IntStream;
import java.util.stream.Stream;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.context.annotation.Configuration;
import org.springframework.scheduling.annotation.EnableAsync;
import org.springframework.scheduling.annotation.EnableScheduling;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;
import reactor.core.publisher.Flux;
import reactor.core.publisher.Mono;

@Slf4j
@Configuration
@EnableScheduling
@EnableAsync
@RequiredArgsConstructor
@RestController
@RequestMapping("/tariff")
public class TariffScheduler {

	private final SAPService sapService;

	private final TariffRepository tariffRepository;

	private final ChartDateUtil chartDateUtil;

	@GetMapping
	public Mono<Map<String, String>> cache() {
		log.info("Start caching tariff to redis cache...");
		return Flux
			.fromStream(
					Stream.iterate(LocalDate.now(), date1 -> date1.minusMonths(6)).limit(3).map(LocalDate::toString))
			.flatMap(dateStr -> sapService
				.reactivePost(TariffSAP.PATH, Request.builder().date(dateStr).build(), Response.class)
				.flatMapIterable(Response::getTariffs)
				.flatMap(tariff -> {
					LocalDate startDate = LocalDate.parse(tariff.getDateFrom(), Constants.FORMATTER_YYYY_MM_DD);
					LocalDate endDate = tariff.getDateTo().equals("9999-12-31")
							? LocalDate.parse(dateStr, Constants.FORMATTER_YYYY_MM_DD)
							: LocalDate.parse(tariff.getDateTo(), Constants.FORMATTER_YYYY_MM_DD);
					int count = (int) ChronoUnit.MONTHS.between(startDate, endDate);
					return Flux.fromStream(IntStream.range(0, count + 1)
						.boxed()
						.map(addMonth -> TariffEntity.Request.builder()
							.date(chartDateUtil
								.format(LocalDate.parse(tariff.getDateFrom(), Constants.FORMATTER_YYYY_MM_DD)
									.plusMonths(addMonth), Constants.FORMATTER_YYYY_MM_DD))
							.tariff(tariff.getElect())
							.build()));
				}))
			.collectList()
			.map(list -> list.stream()
				.collect(Collectors.toMap(TariffEntity.Request::getDate, TariffEntity.Request::getTariff,
						(existing, replacement) -> existing, TreeMap::new)))
			.flatMap(map -> tariffRepository.setAndGet(ChartConstants.TARIFF_REDIS_KEY,
					TariffEntity.Response.builder().mTariffRes(map).build()));
	}

	public Mono<Map<String, String>> get() {
		return tariffRepository.get();
	}

}

