@SpringBootTest(classes = TariffRepositoryImpl.class)
public class TariffRepositoryImplTest {

	@Autowired
	private TariffRepository tariffRepository;

	@MockitoBean
	private ReactiveRedisOperations<String, TariffEntity.Response> tariffEntityRro;

	@MockitoBean
	private ReactiveValueOperations<String, TariffEntity.Response> tariffEntityRvo;

	private String tariffKey, tariffDate, tariffValue;

	private Map<String, String> tariffMap;

	@BeforeAll
	private void init() {
		tariffKey = ChartConstants.TARIFF_REDIS_KEY;
		tariffDate = "2022-01-01";
		tariffValue = ".02566666";
		tariffMap = new HashMap<>() {
			{
				put(tariffDate, tariffValue);
			}
		};
	}

	@Test
	void setAndGet() {
		when(tariffEntityRro.opsForValue()).thenReturn(tariffEntityRvo);
		when(tariffEntityRro.opsForValue().set(any(), any(), any())).thenReturn(Mono.just(Boolean.TRUE));
		StepVerifier
			.create(tariffRepository.setAndGet(ChartConstants.TARIFF_REDIS_KEY,
					TariffEntity.Response.builder().mTariffRes(tariffMap).build()))
			.expectNext(tariffMap)
			.verifyComplete();
	}

	@Test
	void get() {
		when(tariffEntityRro.opsForValue()).thenReturn(tariffEntityRvo);
		when(tariffEntityRro.opsForValue().get(any()))
			.thenReturn(Mono.just(TariffEntity.Response.builder().mTariffRes(tariffMap).build()));
		StepVerifier.create(tariffRepository.get()).expectNext(tariffMap).verifyComplete();
	}

	@Test
	void getTariff() {
		when(tariffEntityRro.opsForValue()).thenReturn(tariffEntityRvo);
		when(tariffEntityRro.opsForValue().get(any()))
			.thenReturn(Mono.just(TariffEntity.Response.builder().mTariffRes(tariffMap).build()));
		StepVerifier.create(tariffRepository.getTariff(tariffDate)).expectNext(tariffValue).verifyComplete();
	}

}

