public interface UserService {

	/**
	 * Method to perform any cleanup that the system stored, whether in cache (redis) or
	 * in database, after authentication.
	 * @param token The token object representation that came from the request (header)
	 * @return Will always return no matter what the exceptions/errors are.
	 */
	Mono<Void> logout(String token, String requestMode);

	/**
	 * Loads all user related details and its associated accounts (EBS/MSSL) from SAP PO
	 * endpoints using the JSON Web Token (JWT). This is in the assumption that this
	 * method will be called when the user is successfully authenticated from the OAuth
	 * 2.0 provider (Auth0).
	 * @param token The object representation of JWT.
	 * @return A {@link UserPremises} reactive object containing the user details and its
	 * associated accounts and premises.
	 */
	Mono<UserPremises> getUserPremises(JwtDecodedToken token);

	/**
	 * Calls super RFC SAP PO and returns details of single account (either EBS or MSSL).
	 * This is in the assumption that this method will be called when the user is
	 * successfully authenticated from the OAuth 2.0 provider (Auth0).
	 * @param token The updated {@link JwtDecodedToken} instance from authentication.
	 * @return A {@link UserPremises} reactive object containing the details of single
	 * account.
	 */
	Mono<UserPremises> getSinglePremise(JwtDecodedToken jwtDecodedToken, String accountNo);

	/**
	 * A convenience method to refresh the existing {@link UserAccount} redis cache entry.
	 * If somehow the entry is not found from redis cache, it internally calls the
	 * {@link #getUserPremises(JwtDecodedToken token)} therefore re-entering the new
	 * {@link UserAccount} redis entry with the updated expiration time from the token.
