package io.spdigital.skalbox.data.redis;

import io.spdigital.skalbox.chart.model.dto.ChartConstants;
import io.spdigital.skalbox.data.redis.TariffEntity.Response;
import lombok.RequiredArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.data.redis.core.ReactiveRedisOperations;
import org.springframework.stereotype.Component;
import reactor.core.publisher.Mono;

import java.time.Duration;
import java.util.Map;

@Slf4j
@Component
@RequiredArgsConstructor
public class TariffRepositoryImpl implements TariffRepository {

	@Value("${redis.redisTariffDataTtl}")
	private int redisTariffDataTtl;

	private final ReactiveRedisOperations<String, TariffEntity.Response> tariffRro;

	@Override
	public Mono<Map<String, String>> setAndGet(String key, Response value) {
		return tariffRro.opsForValue()
			.set(key, value, Duration.ofDays(redisTariffDataTtl))
			.map(aBoolean -> value.getMTariffRes());
	}

	@Override
	public Mono<Map<String, String>> get() {
		return tariffRro.opsForValue().get(ChartConstants.TARIFF_REDIS_KEY).map(val -> val.getMTariffRes());
	}

	@Override
	public Mono<String> getTariff(String key) {
		return this.get().map(taMap -> taMap.get(key));
	}

}

package io.spdigital.skalbox.web.common.security;

import io.spdigital.skalbox.service.security.Field;
import io.spdigital.skalbox.service.security.State;

import java.lang.annotation.*;

@Target(ElementType.METHOD)
@Retention(RetentionPolicy.RUNTIME)
@Documented
public @interface SkalboxSecured {

	/**
	 * @return The state of security evaluation to perform for the {@link #field()}.
	 */
	State state() default State.SECURED;

	/**
	 * @return The field type to which the security evaluation to execute from.
	 */
	Field field() default Field.ACCOUNT_NO;

	/**
	 * @return Flag which determines if the exact match should be check.
	 */
	boolean strict() default false;

	/**
	 * @return The custom field name to evaluate the security execution.
	 */
	String customFieldName() default "";

}

