package io.spdigital.skalbox.data.redis;

import lombok.RequiredArgsConstructor;
import org.springframework.data.redis.core.ReactiveRedisOperations;
import org.springframework.stereotype.Component;
import reactor.core.publisher.Mono;

import java.time.Duration;
import java.time.temporal.ChronoUnit;

@Component
@RequiredArgsConstructor
public class UserAccountRepositoryImpl implements UserAccountRepository {

	private final ReactiveRedisOperations<String, UserAccountEntity> userAccountEntityRro;

	@Override
	public Mono<Boolean> save(UserAccountEntity userAccountEntity) {
		return userAccountEntityRro.opsForValue()
			.set(userAccountEntity.getUserId(), userAccountEntity,
					Duration.of(userAccountEntity.getExpiration(), ChronoUnit.SECONDS));
	}

	@Override
	public Mono<UserAccountEntity> get(String userId) {
		return userAccountEntityRro.opsForValue().get(userId);
	}

	@Override
	public Mono<Boolean> delete(String userId) {
		return userAccountEntityRro.opsForValue().delete(userId);
	}

}

